@else<div class="overflow-x-auto"><table class="w-full text-sm"><thead class="bg-gray-50"><tr><th class="px-3 py-2 text-left text-xs">N</th><th class="px-3 py-2 text-left text-xs">Date</th><th class="px-3 py-2 text-left text-xs">Montant</th><th class="px-3 py-2 text-left text-xs">Mode</th><th class="px-3 py-2 text-left text-xs">Statut</th><th class="px-3 py-2 text-left text-xs">Ref</th></tr></thead><tbody class="divide-y">
@foreach($payments as $pay)<tr><td class="px-3 py-2 font-mono text-xs">{{ $pay->payment_number }}</td><td class="px-3 py-2 text-xs">{{ $pay->payment_date?->format('d/m/Y') }}</td><td class="px-3 py-2 font-medium">{{ number_format($pay->amount,2,',',' ') }} &euro;</td><td class="px-3 py-2"><span class="px-2 py-0.5 bg-gray-100 text-gray-700 rounded text-xs">{{ match($pay->method){'card'=>'CB','sepa'=>'SEPA','check'=>'Cheque','transfer'=>'Virement','cash'=>'Especes','free'=>'Gratuit',default=>$pay->method} }}</span></td><td class="px-3 py-2"><span class="px-2 py-0.5 rounded-full text-xs {{ $pay->status==='completed'?'bg-green-100 text-green-800':($pay->status==='pending'?'bg-yellow-100 text-yellow-800':'bg-gray-100 text-gray-600') }}">{{ match($pay->status){'completed'=>'Encaisse','pending'=>'En attente','failed'=>'Echoue','refunded'=>'Rembourse',default=>$pay->status} }}</span></td><td class="px-3 py-2 text-xs">{{ $pay->reference ?? '-' }}</td></tr>@endforeach
</tbody><tfoot class="bg-gray-50 font-medium"><tr><td colspan="2" class="px-3 py-2 text-right">Total encaisse</td><td class="px-3 py-2">{{ number_format($payments->where('status','completed')->sum('amount'),2,',',' ') }} &euro;</td><td colspan="3"></td></tr></tfoot></table></div>@endif
